#[cfg(test)]
mod tests {
    use super::*;
    use axum::{body::Body, http::{Request, HeaderValue}, middleware};
    use axum::{Router, routing::get};
    use tower::ServiceExt; // for `.oneshot()`
    use sqlx::PgPool;

    async fn dummy_handler() -> &'static str { "ok" }

    // Test 1: request with no x-api-key header → 401
    #[sqlx::test]
    async fn missing_api_key_returns_401(pool: PgPool) {
        let app = Router::new()
            .route("/", get(dummy_handler))
            .route_layer(middleware::from_fn_with_state(pool, require_api_key));

        let req = Request::builder().uri("/").body(Body::empty()).unwrap();
        let res = app.oneshot(req).await.unwrap();
        assert_eq!(res.status(), 401);
    }

    // Test 2: request with wrong api key → 401
    #[sqlx::test]
    async fn wrong_api_key_returns_401(pool: PgPool) {
        let app = Router::new()
            .route("/", get(dummy_handler))
            .route_layer(middleware::from_fn_with_state(pool, require_api_key));

        let req = Request::builder()
            .uri("/")
            .header("x-api-key", "not-a-real-key")
            .body(Body::empty()).unwrap();
        let res = app.oneshot(req).await.unwrap();
        assert_eq!(res.status(), 401);
    }

    // Test 3: valid api key → tenant injected, request proceeds
    #[sqlx::test]
    async fn valid_api_key_injects_tenant(pool: PgPool) {
        // seed a key into the pool-provided test DB
        let raw_key = "my-test-key";
        let hash = sha256_hex(raw_key); // extract hashing into a helper fn
        sqlx::query("INSERT INTO api_keys (key_hash, tenant_id) VALUES ($1, $2)")
            .bind(&hash).bind("tenant-test")
            .execute(&pool).await.unwrap();

        let app = Router::new()
            .route("/", get(dummy_handler))
            .route_layer(middleware::from_fn_with_state(pool, require_api_key));

        let req = Request::builder()
            .uri("/")
            .header("x-api-key", raw_key)
            .body(Body::empty()).unwrap();
        let res = app.oneshot(req).await.unwrap();
        assert_eq!(res.status(), 200);
    }
}
```

> **Note:** The SHA-256 hashing logic is embedded directly in `require_api_key`. Extract it into a `fn sha256_hex(input: &str) -> String` helper so it can be unit-tested independently.

